"""
This module contains the command-line interface for playing Checkers.
"""

from checkers_game import CheckersGame

def main():
    game = CheckersGame()
    while True:
        game.board.print_board()
        current_player = game.get_current_player()
        print(f"{current_player.name}'s turn ({current_player.color})")

        start_pos = input("Enter start position (row col): ").split()
        end_pos = input("Enter end position (row col): ").split()

        start_pos = tuple(map(int, start_pos))
        end_pos = tuple(map(int, end_pos))

        move = Move(start_pos, end_pos)
        game.make_move(move)

if __name__ == "__main__":
    main()
